//! Typed access to the `amx_*` functions exported by the server.
//!
//! The server exposes `amx_Exports` (passed in `Load()`) as a flat table of
//! pointers, indexed by the values of [`Exports`]. Each function has a
//! zero-sized marker type (generated by `impl_export!`) that carries the
//! corresponding offset in [`Export::OFFSET`] and the function type in [`Export::Output`].
//!
//! Typical usage: `Exec::from_table(fn_table)` returns the typed pointer.
//! Resolving on demand avoids storing all 44 pointers in [`crate::amx::Amx`].

use crate::raw::functions;

macro_rules! impl_export {
    ($name:ident) => {
        pub struct $name;

        impl Export for $name {
            type Output = functions::$name;
            const OFFSET: isize = Exports::$name as isize;

            #[inline(always)]
            fn from_table(fn_table: usize) -> Self::Output {
                assert!(fn_table != 0, "from_table() received null fn_table");
                let table = fn_table as *const usize;

                unsafe {
                    let ptr = table.offset(Self::OFFSET);
                    assert!(
                        ptr.read() != 0,
                        "from_table() function at offset {} is null",
                        Self::OFFSET
                    );
                    ptr.cast::<Self::Output>().read()
                }
            }
        }
    };
}

/// Retrieves a typed pointer from the `amx_Exports` table.
pub trait Export {
    /// Type of the exported function — alias declared in [`crate::raw::functions`].
    type Output;

    /// Offset of this function in the table. Values correspond 1:1 to [`Exports`].
    const OFFSET: isize;

    /// Reads the pointer at offset `OFFSET` of the `fn_table` table.
    ///
    /// # Panics
    /// In debug mode, panics if `fn_table` is null or if the read pointer is
    /// null (indicates a non-conforming server or a corrupted table).
    fn from_table(fn_table: usize) -> Self::Output;
}

impl_export!(Align16);
impl_export!(Align32);
impl_export!(Allot);
impl_export!(Callback);
impl_export!(Cleanup);
impl_export!(Clone);
impl_export!(Exec);
impl_export!(FindNative);
impl_export!(FindPublic);
impl_export!(FindPubVar);
impl_export!(FindTagId);
impl_export!(Flags);
impl_export!(GetAddr);
impl_export!(GetNative);
impl_export!(GetPublic);
impl_export!(GetPubVar);
impl_export!(GetString);
impl_export!(GetTag);
impl_export!(GetUserData);
impl_export!(Init);
impl_export!(InitJIT);
impl_export!(MemInfo);
impl_export!(NameLength);
impl_export!(NativeInfo);
impl_export!(NumNatives);
impl_export!(NumPublics);
impl_export!(NumPubVars);
impl_export!(NumTags);
